import os
import psycopg2
from psycopg2 import pool
from contextlib import contextmanager


def get_db_config():
    """
    Load database configuration from environment variables.

    Set these environment variables before running:
        export DB_HOST=localhost
        export DB_PORT=5432
        export DB_NAME=hackathon_db
        export DB_USER=admin
        export DB_PASSWORD=demo123
    """
    required_vars = ["DB_HOST", "DB_PORT", "DB_NAME", "DB_USER", "DB_PASSWORD"]
    missing = [var for var in required_vars if not os.environ.get(var)]

    if missing:
        raise EnvironmentError(
            f"Missing required environment variables: {', '.join(missing)}. "
            f"Please set them before running the application.\n"
            f"Example:\n"
            f"  export DB_HOST=localhost\n"
            f"  export DB_PORT=5432\n"
            f"  export DB_NAME=hackathon_db\n"
            f"  export DB_USER=admin\n"
            f"  export DB_PASSWORD=<your_password>"
        )

    return {
        "host": os.environ["DB_HOST"],
        "port": int(os.environ["DB_PORT"]),
        "dbname": os.environ["DB_NAME"],
        "user": os.environ["DB_USER"],
        "password": os.environ["DB_PASSWORD"],
    }


_connection_pool = None


def initialize_connection_pool(min_connections=1, max_connections=10):
    """Initialize a connection pool for the PostgreSQL database."""
    global _connection_pool
    if _connection_pool is not None:
        return _connection_pool

    config = get_db_config()
    _connection_pool = psycopg2.pool.ThreadedConnectionPool(
        minconn=min_connections,
        maxconn=max_connections,
        host=config["host"],
        port=config["port"],
        dbname=config["dbname"],
        user=config["user"],
        password=config["password"],
    )
    return _connection_pool


def get_connection():
    """Get a connection from the pool."""
    global _connection_pool
    if _connection_pool is None:
        initialize_connection_pool()
    return _connection_pool.getconn()


def release_connection(conn):
    """Return a connection to the pool."""
    global _connection_pool
    if _connection_pool is not None:
        _connection_pool.putconn(conn)


@contextmanager
def get_db_connection():
    """
    Context manager that provides a database connection from the pool.

    Usage:
        with get_db_connection() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT 1")
                result = cur.fetchone()
    """
    conn = get_connection()
    try:
        yield conn
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        release_connection(conn)


@contextmanager
def get_db_cursor(commit=True):
    """
    Context manager that provides a database cursor.

    Usage:
        with get_db_cursor() as cur:
            cur.execute("SELECT * FROM users WHERE id = %s", (user_id,))
            row = cur.fetchone()
    """
    with get_db_connection() as conn:
        cursor = conn.cursor()
        try:
            yield cursor
            if commit:
                conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            cursor.close()


def close_all_connections():
    """Close all connections in the pool."""
    global _connection_pool
    if _connection_pool is not None:
        _connection_pool.closeall()
        _connection_pool = None


def test_connection():
    """Test the database connection and print status."""
    try:
        with get_db_cursor() as cur:
            cur.execute("SELECT version();")
            version = cur.fetchone()
            print(f"Connected successfully. PostgreSQL version: {version[0]}")
            return True
    except EnvironmentError as e:
        print(f"Configuration error: {e}")
        return False
    except psycopg2.OperationalError as e:
        print(f"Connection failed: {e}")
        return False


